export type IconName = keyof typeof ICON_PATHS;

export interface IconProps {
  name: string;
  size?: number;
  strokeWidth?: number;
  className?: string;
  title?: string;
}

/** One SVG renderer for every icon. Unknown names render nothing (caller shows
 *  a text fallback), so a missing glyph never throws. */
export function Icon({ name, size = 20, strokeWidth = 2, className, title }: IconProps) {
  const paths = ICON_PATHS[name];
  if (!paths) return null;
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth={strokeWidth}
      strokeLinecap="round"
      strokeLinejoin="round"
      className={className}
      role="img"
      aria-hidden={title ? undefined : true}
      aria-label={title}
    >
      {paths.map((p, i) =>
        typeof p === 'string' ? (
          <path key={i} d={p} />
        ) : (
          <path key={i} d={p.d} fill="currentColor" stroke="none" />
        ),
      )}
    </svg>
  );
}

export const hasIcon = (name: string): boolean => name in ICON_PATHS;
